PREFIX wdt: <http://www.wikidata.org/prop/direct/>
PREFIX wd: <http://www.wikidata.org/entity/>

SELECT DISTINCT (YEAR(?endTime) AS ?year)
WHERE {
  ?season wdt:P31 wd:Q6216 ;
          wdt:P1545 wd:Q157376 ;
          wdt:P582 ?endTime .
  FILTER(YEAR(?endTime) <= YEAR(NOW()))
}
ORDER BY ?endTime

